<span class="line"><span style="color:#C678DD;">    def</span><span style="color:#61AFEF;"> test_insert_data</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;font-style:italic;">self</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;font-style:italic;">db_connection</span><span style="color:#ABB2BF;">):</span></span>
