<span class="line"><span style="color:#ABB2BF;">            users </span><span style="color:#56B6C2;">=</span><span style="color:#ABB2BF;"> cursor.</span><span style="color:#61AFEF;">fetchall</span><span style="color:#ABB2BF;">()</span></span>
