<span class="line"><span style="color:#ABB2BF;">            updated_at </span><span style="color:#56B6C2;">=</span><span style="color:#ABB2BF;"> cursor.</span><span style="color:#61AFEF;">fetchone</span><span style="color:#ABB2BF;">()[</span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">]</span></span>
