<span class="line"><span style="color:#C678DD;">            with</span><span style="color:#ABB2BF;"> db_connection.</span><span style="color:#61AFEF;">cursor</span><span style="color:#ABB2BF;">() </span><span style="color:#C678DD;">as</span><span style="color:#ABB2BF;"> cursor:</span></span>
