<span class="line"><span style="color:#98C379;">                    &quot;INSERT INTO users (username, email, password, age) VALUES (</span><span style="color:#D19A66;">%s</span><span style="color:#98C379;">, </span><span style="color:#D19A66;">%s</span><span style="color:#98C379;">, </span><span style="color:#D19A66;">%s</span><span style="color:#98C379;">, </span><span style="color:#D19A66;">%s</span><span style="color:#98C379;">)&quot;</span><span style="color:#ABB2BF;">,</span></span>
