<span class="line"><span style="color:#ABB2BF;">                cursor.</span><span style="color:#61AFEF;">execute</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;SELECT COUNT(*) FROM users WHERE username LIKE &#39;txuser%&#39;&quot;</span><span style="color:#ABB2BF;">)</span></span>
